fn sm_seg(p: vec2f, a: vec2f, b: vec2f) -> f32 {
  let pa = p - a;
  let ba = b - a;
  let h = clamp(dot(pa, ba) / max(dot(ba, ba), 1e-6), 0.0, 1.0);
  return length(pa - ba * h);
}

fn visual_smug_planet(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let t = time;
  let gaze = vec2f(uni(0), uni(1));
  let lid = clamp(uni(2), 0.0, 1.0);
  let smile = clamp(uni(3), 0.0, 1.0);
  let pulse = uni(4);
  let blush = clamp(uni(5), 0.0, 1.0);
  let sleep = clamp(uni(6), 0.0, 1.0);
  let glow = clamp(uni(7), 0.0, 1.0);

  // ── a sky that flatters the planet ──
  var col = mix(vec3f(0.10, 0.06, 0.16), vec3f(0.03, 0.02, 0.08), clamp(uv.y * 0.7 + 0.5, 0.0, 1.0));
  let sp = uv * 13.0;
  let sh = hash21(floor(sp));
  if (sh > 0.975) {
    col += vec3f(0.7, 0.72, 0.9) * smoothstep(0.22, 0.03, length(fract(sp) - 0.5)) * (0.4 + 0.4 * sin(t * 1.6 + sh * 40.0));
  }
  // drifting haze
  col += vec3f(0.10, 0.06, 0.14) * fbm(uv * 2.0 + vec2f(t * 0.015, 0.0), 3) * 0.5;

  // ── the admirer: a small moon with the same attitude ──
  let ma = t * 0.35;
  let mc = vec2f(cos(ma), sin(ma) * 0.62) * 0.72;
  let mr = length(uv - mc);
  if (mr < 0.075) {
    var mcol = mix(vec3f(0.75, 0.72, 0.80), vec3f(0.45, 0.42, 0.55), (uv.y - mc.y) / 0.075 * 0.5 + 0.5);
    let mq = (uv - mc) / 0.075;
    // two half-lidded dots and a micro-smirk
    if (mq.y > -0.25 && (length(mq - vec2f(-0.3, -0.12)) < 0.11 || length(mq - vec2f(0.3, -0.12)) < 0.11)) { mcol = vec3f(0.08, 0.07, 0.10); }
    if (sm_seg(mq, vec2f(-0.12, 0.3), vec2f(0.22, 0.22)) < 0.05) { mcol = vec3f(0.08, 0.07, 0.10); }
    col = mcol;
  }
  col += vec3f(0.5, 0.48, 0.6) * exp(-mr * mr * 160.0) * 0.25;

  // ── the planet itself ──
  let R = 0.42;
  let d = length(uv);
  if (d < R) {
    let q = uv / R;                                   // -1..1 planet space
    // terrain bands, subtly luxurious
    var base = mix(vec3f(0.85, 0.55, 0.30), vec3f(0.95, 0.72, 0.38), fbm(q * 3.0 + 2.0, 3));
    base = mix(base, vec3f(0.70, 0.38, 0.45), smoothstep(0.3, 0.8, fbm(q * 2.2 + 9.0, 3)) * 0.5);
    // lit from upper left, like it hired the lighting
    let n = vec3f(q, sqrt(max(1.0 - dot(q, q), 0.0)));
    let l = normalize(vec3f(-0.5, -0.6, 0.7));
    base *= 0.45 + 0.75 * max(dot(n, l), 0.0);
    base += vec3f(0.9, 0.7, 0.4) * pow(1.0 - abs(n.z), 2.5) * 0.35;   // rim light
    col = base;

    // ── the face ──
    let openness = 1.0 - max(lid, sleep);
    for (var e = 0; e < 2; e++) {
      let ex = select(-0.30, 0.30, e == 1);
      let ec = vec2f(ex, -0.10);
      let eq = (q - ec) / vec2f(0.16, 0.13);
      let ed = length(eq);
      if (ed < 1.0) {
        // eye white, then iris that follows (or snubs) you
        col = mix(col, vec3f(0.96, 0.94, 0.90), smoothstep(1.0, 0.85, ed));
        let iris = (q - ec - gaze * 0.055) / 0.065;
        let id2 = length(iris);
        if (id2 < 1.0) {
          col = mix(col, vec3f(0.20, 0.12, 0.08), smoothstep(1.0, 0.7, id2));
          if (length(iris - vec2f(0.3, -0.3)) < 0.3) { col = vec3f(0.98, 0.96, 0.92); }  // the gleam
        }
        // the lid: smugness is measured in eyelid coverage
        let lidY = -1.0 + 2.0 * (0.42 + 0.58 * max(lid, sleep));
        if (eq.y < lidY) { col = mix(col, vec3f(0.80, 0.50, 0.30), smoothstep(lidY - 0.12, lidY, eq.y) * 0.0 + 1.0); }
        if (abs(eq.y - lidY) < 0.07 && ed < 1.0) { col = vec3f(0.45, 0.25, 0.18); }   // lash line
      }
    }
    // one raised brow (the left one, obviously)
    if (sm_seg(q, vec2f(-0.42, -0.34), vec2f(-0.18, -0.40)) < 0.022) { col = vec3f(0.35, 0.18, 0.12); }
    if (sm_seg(q, vec2f(0.18, -0.30), vec2f(0.42, -0.28)) < 0.022) { col = vec3f(0.35, 0.18, 0.12); }
    // the smirk: one corner up, always
    let curl = 0.10 + smile * 0.16;
    let s0 = vec2f(-0.16, 0.28);
    let s1 = vec2f(0.05, 0.30 + smile * 0.03);
    let s2 = vec2f(0.24, 0.28 - curl);
    if (sm_seg(q, s0, s1) < 0.028 || sm_seg(q, s1, s2) < 0.028) { col = vec3f(0.40, 0.20, 0.14); }
    // the dimple at the raised corner
    if (length(q - (s2 + vec2f(0.045, -0.02))) < 0.022) { col = vec3f(0.45, 0.24, 0.16); }
    // blush of self-regard
    col += vec3f(0.55, 0.12, 0.10) * blush * (exp(-dot(q - vec2f(-0.52, 0.16), q - vec2f(-0.52, 0.16)) * 30.0)
                                            + exp(-dot(q - vec2f(0.52, 0.16), q - vec2f(0.52, 0.16)) * 30.0));
    // zzz while pretending to sleep
    if (sleep > 0.5) {
      let zt = fract(t * 0.4);
      let zp = q - vec2f(0.55 + zt * 0.25, -0.55 - zt * 0.35);
      if (sm_seg(zp, vec2f(-0.03, -0.03), vec2f(0.03, -0.03)) < 0.012 ||
          sm_seg(zp, vec2f(0.03, -0.03), vec2f(-0.03, 0.03)) < 0.012 ||
          sm_seg(zp, vec2f(-0.03, 0.03), vec2f(0.03, 0.03)) < 0.012) {
        col = mix(col, vec3f(0.95, 0.95, 1.0), 1.0 - zt);
      }
    }
  }
  // contented aura + click ring
  col += vec3f(1.0, 0.75, 0.35) * exp(-pow((d - R - 0.02) * 18.0, 2.0)) * (0.25 + glow * 0.9);
  if (pulse > 0.001) {
    let rr = R + (1.0 - pulse) * 0.55;
    col += vec3f(1.0, 0.8, 0.4) * exp(-pow((d - rr) * 22.0, 2.0)) * pulse * 0.8;
  }
  if (col.x != col.x || col.y != col.y || col.z != col.z) { col = vec3f(0.02); }
  return vec4f(clamp(col, vec3f(0.0), vec3f(20.0)), 1.0);
}
